import json
path = var_call_21ygs24gVOzF15jJz1YZcBPK
with open(path,'r',encoding='utf-8') as f:
    data = json.load(f)

lines = []
for r in data:
    title = r.get('title')
    author = r.get('author')
    name = None
    if isinstance(author, str) and author and author.strip().startswith('{'):
        try:
            a = json.loads(author)
            name = a.get('name')
        except Exception:
            name = None
    if not name:
        if author in [None, 'None', '']:
            name = None
        else:
            name = author
    if name:
        lines.append(str(title) + " — " + str(name))
    else:
        lines.append(str(title) + " — Unknown author")

answer = "\\n".join(lines) if lines else "No matching books found."

print('__RESULT__:')
print(json.dumps(answer, ensure_ascii=False))

